 29→    icon: '💐',
 30→    photo: '/images/couple/ashirwad_044.jpg',
 31→  },
 32→  {
 33→    year: 'Coming Soon',
 34→    title: 'শুভ বিবাহ',
 35→    description:
 36→      'The Ashirwad was the prologue — beautiful, emotional, unforgettable. But the best chapters are still being written. The wedding is on the horizon, and with it, a new beginning. Stay with us for what comes next in Rituparna and Shoumo\'s love story. সবাই আমন্ত্রিত — everyone is invited to witness this next chapter.',
 37→    icon: '💍',
 38→    photo: null,
 39→  },
 40→];
