 42→export default function OurStory() {
 43→  return (
 44→    <section
 45→      id="our-story"
 46→      className="py-28 md:py-32 px-6 bg-white dark:bg-[#1f1118]"
 47→    >
 48→      <div className="max-w-4xl mx-auto">
 49→        {/* Section header */}
 50→        <motion.div
 51→          initial={{ opacity: 0, y: 30 }}
 52→          whileInView={{ opacity: 1, y: 0 }}
 53→          viewport={{ once: true }}
 54→          transition={{ duration: 0.7 }}
 55→          className="text-center mb-16 md:mb-20"
 56→        >
 57→          <div className="flex items-center justify-center gap-4 mb-6">
 58→            <div className="h-px w-12 bg-blush-200 dark:bg-blush-800" />
 59→            <FiHeart className="text-blush-500" size={16} />
 60→            <div className="h-px w-12 bg-blush-200 dark:bg-blush-800" />
 61→          </div>
 62→          <h2 className="font-script text-5xl md:text-6xl text-blush-700 dark:text-blush-300 mb-4">
 63→            Our Story
 64→          </h2>
 65→          <p className="font-serif text-lg md:text-xl text-[#2d1a24]/60 dark:text-blush-200/60 max-w-xl mx-auto leading-relaxed">
 66→            ভালোবাসার গল্প — a story written in blessings, garlands, and the laughter of family.
