 69→
 70→        {/* Timeline */}
 71→        <div className="relative">
 72→          {/* Vertical line */}
 73→          <div className="absolute left-1/2 -translate-x-1/2 top-0 bottom-0 w-px bg-gradient-to-b from-transparent via-blush-200 dark:via-blush-800 to-transparent hidden md:block" />
 74→
 75→          <div className="space-y-14 md:space-y-16">
 76→            {milestones.map((milestone, i) => (
 77→              <motion.div
 78→                key={milestone.year}
 79→                initial={{ opacity: 0, x: i % 2 === 0 ? -40 : 40 }}
 80→                whileInView={{ opacity: 1, x: 0 }}
 81→                viewport={{ once: true }}
 82→                transition={{ duration: 0.6, delay: i * 0.1, ease: [0.25, 0.1, 0.25, 1.0] }}
 83→                className={`flex flex-col md:flex-row items-center gap-8 ${
 84→                  i % 2 === 0 ? 'md:flex-row' : 'md:flex-row-reverse'
 85→                }`}
 86→              >
 87→                {/* Content */}
 88→                <div className="flex-1 text-center md:text-left">
 89→                  <div
 90→                    className={`bg-blush-50 dark:bg-[#2d1020] rounded-2xl p-6 md:p-8 border border-blush-100 dark:border-blush-900/50 shadow-soft hover:shadow-glow transition-all duration-300 ${
 91→                      i % 2 !== 0 ? 'md:text-right' : ''
 92→                    }`}
 93→                  >
 94→                    {/* Photo thumbnail or emoji */}
 95→                    {milestone.photo ? (
 96→                      <div className={`w-20 h-20 rounded-xl overflow-hidden mb-4 ${i % 2 !== 0 ? 'md:ml-auto' : ''} mx-auto md:mx-0`}>
 97→                        <Image
 98→                          src={milestone.photo}
 99→                          alt={milestone.title}
100→                          width={80}
101→                          height={80}
102→                          className="object-cover w-full h-full"
103→                        />
104→                      </div>
105→                    ) : (
106→                      <span className="text-3xl mb-4 block">{milestone.icon}</span>
107→                    )}
108→
109→                    <span className="font-sans text-[10px] tracking-[0.2em] uppercase text-blush-400 dark:text-blush-500 block mb-1">
110→                      {milestone.year}
111→                    </span>
112→                    <h3 className="font-serif text-xl font-semibold text-[#2d1a24] dark:text-blush-100 mb-3">
113→                      {milestone.title}
114→                    </h3>
115→                    <p className="font-sans text-sm text-[#2d1a24]/60 dark:text-blush-200/60 leading-relaxed">
116→                      {milestone.description}
117→                    </p>
118→                  </div>
119→                </div>
