  1→'use client';
  2→
  3→import { useState } from 'react';
  4→import Image from 'next/image';
  5→import { motion } from 'framer-motion';
  6→import { FiHeart, FiChevronDown } from 'react-icons/fi';
  7→import Lightbox from 'yet-another-react-lightbox';
  8→import 'yet-another-react-lightbox/styles.css';
  9→import PhotoGallery, { GalleryPhoto } from './PhotoGallery';
 10→
 11→interface GallerySectionProps {
 12→  id: string;
 13→  title: string;
 14→  subtitle?: string;
 15→  emoji?: string;
 16→  photos: GalleryPhoto[];
 17→  columns?: 2 | 3 | 4;
 18→  bg?: 'white' | 'cream';
 19→  mobileLimit?: number;
 20→}
 21→
 22→export default function GallerySection({
 23→  id,
 24→  title,
 25→  subtitle,
 26→  emoji = '📷',
 27→  photos,
 28→  columns = 3,
 29→  bg = 'cream',
 30→  mobileLimit = 6,
 31→}: GallerySectionProps) {
 32→  const [lightboxIndex, setLightboxIndex] = useState(-1);
 33→  const [mobileExpanded, setMobileExpanded] = useState(false);
 34→
 35→  const bgClass =
 36→    bg === 'white'
 37→      ? 'bg-white dark:bg-[#1f1118]'
 38→      : 'bg-ivory dark:bg-[#1a0f14]';
 39→
 40→  const heroPhoto = photos[0];
 41→  const gridPhotos = photos.slice(1);
 42→
 43→  // On mobile, limit grid photos (hero is always shown)
 44→  const mobileGridLimit = Math.max(0, mobileLimit - 1); // -1 for hero
 45→  const hasMoreOnMobile = gridPhotos.length > mobileGridLimit;
 46→
 47→  return (
 48→    <section id={id} className={`py-28 md:py-32 px-6 ${bgClass}`}>
 49→      <div className="max-w-6xl mx-auto">
 50→        {/* Section header */}
 51→        <motion.div
 52→          initial={{ opacity: 0, y: 30 }}
 53→          whileInView={{ opacity: 1, y: 0 }}
 54→          viewport={{ once: true }}
 55→          transition={{ duration: 0.7, ease: [0.25, 0.1, 0.25, 1.0] }}
 56→          className="text-center mb-16 md:mb-20"
 57→        >
 58→          <div className="flex items-center justify-center gap-4 mb-5">
 59→            <div className="h-px w-12 bg-blush-200 dark:bg-blush-800" />
 60→            <FiHeart className="text-blush-400" size={14} />
 61→            <div className="h-px w-12 bg-blush-200 dark:bg-blush-800" />
 62→          </div>
 63→          <span className="text-4xl block mb-4">{emoji}</span>
 64→          <h2 className="font-script text-5xl md:text-6xl text-blush-700 dark:text-blush-300 mb-3">
 65→            {title}
 66→          </h2>
 67→          {subtitle && (
 68→            <p className="font-serif text-lg md:text-xl text-[#2d1a24]/55 dark:text-blush-200/55 max-w-2xl mx-auto leading-relaxed">
 69→              {subtitle}
 70→            </p>
 71→          )}
 72→        </motion.div>
 73→
 74→        {/* Featured hero photo — full width cinematic crop */}
 75→        {heroPhoto && (
 76→          <motion.div
 77→            initial={{ opacity: 0, y: 20 }}
 78→            whileInView={{ opacity: 1, y: 0 }}
 79→            viewport={{ once: true }}
 80→            transition={{ duration: 0.7, ease: [0.25, 0.1, 0.25, 1.0] }}
 81→            className="relative w-full aspect-[4/3] sm:aspect-[16/9] md:aspect-[21/9] overflow-hidden rounded-2xl mb-8 cursor-pointer group"
 82→            onClick={() => setLightboxIndex(0)}
 83→          >
 84→            <Image
 85→              src={heroPhoto.src}
 86→              alt={heroPhoto.alt}
 87→              fill
 88→              className="object-cover object-top md:object-[center_30%] transition-transform duration-700 group-hover:scale-[1.02]"
 89→              sizes="100vw"
 90→            />
 91→            <div className="absolute inset-0 bg-gradient-to-t from-black/30 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />
 92→          </motion.div>
 93→        )}
 94→
 95→        {/* Desktop: show all grid photos */}
 96→        <div className="hidden sm:block">
 97→          <PhotoGallery
 98→            photos={gridPhotos}
 99→            columns={columns}
100→            lightboxPhotos={photos}
101→            lightboxOffset={1}
102→          />
103→        </div>
104→
105→        {/* Mobile: show limited grid photos with "Show More" */}
106→        <div className="sm:hidden">
107→          <PhotoGallery
108→            photos={mobileExpanded ? gridPhotos : gridPhotos.slice(0, mobileGridLimit)}
109→            columns={columns}
110→            lightboxPhotos={photos}
111→            lightboxOffset={1}
112→          />
113→          {hasMoreOnMobile && !mobileExpanded && (
114→            <motion.button
115→              initial={{ opacity: 0 }}
116→              animate={{ opacity: 1 }}
117→              onClick={() => setMobileExpanded(true)}
118→              className="mt-8 mx-auto flex items-center gap-2 px-6 py-3 rounded-full bg-blush-100 dark:bg-blush-900/30 text-blush-700 dark:text-blush-300 font-sans text-sm tracking-wide hover:bg-blush-200 dark:hover:bg-blush-900/50 transition-colors"
119→            >
120→              Show {gridPhotos.length - mobileGridLimit} more
121→              <FiChevronDown size={16} />
122→            </motion.button>
123→          )}
124→        </div>
125→      </div>
126→
127→      {/* Lightbox for hero photo click */}
128→      <Lightbox
129→        open={lightboxIndex >= 0}
130→        index={lightboxIndex}
131→        close={() => setLightboxIndex(-1)}
132→        slides={photos.map((p) => ({ src: p.src, alt: p.alt }))}
133→      />
134→    </section>
135→  );
136→}
